    let n = nums.count
    var prefixSum = [Int64](repeating: 0, count: n + 1)
    for i in 1...n {
        prefixSum[i] = prefixSum[i-1] + nums[i-1]
    }
    var dp = [Int64](repeating: 0, count: n + 1)
    var modMap: [Int64: Int64] = [:]
