import Foundation

func solve(nums: [Int64], k: Int64) -> Int64 {
    var prefixSum = 0
    var dp = 0
    var modMap: [Int64: Int64] = [0: 0]

    for num in nums {
        prefixSum += num
        let currentMod = prefixSum % k
        var candidate: Int64 = -Int64(Int32.max)
        if let value = modMap[currentMod] {
            candidate = value + prefixSum
        }
        let newDp = max(dp, candidate)

        var newEntry: Int64
        if let existing = modMap[currentMod] {
            newEntry = max(existing, newDp - prefixSum)
        } else {
            newEntry = newDp - prefixSum
        }
        modMap[currentMod] = newEntry
        dp = newDp
    }

    let totalSum: Int64 = nums.reduce(0) { $0 + $1 }
    return totalSum - dp
}
