func solve(nums: [Int64], k: Int64) -> Int64 {
    var total_sum = 0
    for num in nums {
        total_sum += num
    }
    var pre = 0
    var dp_prev = 0
    var rem_map: [Int64: Int64] = [0: 0]
    for num in nums {
        pre += num
        let remainder = pre % k
        let current_max = rem_map[remainder] ?? -Int64.max
        let candidate = current_max + pre
        let dp_current = max(dp_prev, candidate)
        var new_value = dp_current - pre
        if let existing = rem_map[remainder] {
            if new_value > existing {
                rem_map[remainder] = new_value
            }
        } else {
            rem_map[remainder] = new_value
        }
        dp_prev = dp_current
    }
    return total_sum - dp_prev
}
